# ── Función: momentos teóricos de la medida de Haar ──────────
def haar_moments(N):
    """
    Calcula los momentos teóricos de la medida de Haar de E_N
    restringida al arco (N, 2N), en coordenadas R = T/N ∈ (1,2).

    Densidad en R: p(R) ∝ 1/sqrt(R³ - R) = 1/sqrt(R(R-1)(R+1))
    (resultado de la sustitución T = NR en dT/sqrt(T³-N²T))

    La densidad es independiente de N en coordenadas R — lo que
    significa que TODOS los N congruentes tienen la misma medida
    de Haar teórica sobre (1,2). Esto es una propiedad fundamental.

    Retorna: (Z, mu, sigma, M3, M4, M6, freq_teorica)
    donde freq_teorica = fracción de C_inf que ocupa el arco,
    estimada via el período relativo de la curva.
    """
    # Densidad sin normalizar: f(R) = 1/sqrt(R(R-1)(R+1))
    # Singularidad integrable en R=1 (y=0 en el punto de 2-torsión)
    def f(R):
        val = R * (R - _sage_const_1p0 ) * (R + _sage_const_1p0 )
        if val <= _sage_const_0 :
            return _sage_const_0p0 
        return _sage_const_1p0  / np.sqrt(val)

    # Constante normalizadora Z = integral de 1 a 2 de f(R) dR
    # Usamos puntos de cuadratura que evitan la singularidad en R=1
    Z, _ = integrate.quad(f, _sage_const_1p0 , _sage_const_2p0 ,
                          limit=_sage_const_200 ,
                          points=[_sage_const_1p001 , _sage_const_1p01 , _sage_const_1p05 ],
                          epsabs=_sage_const_1en10 , epsrel=_sage_const_1en10 )

    # Media teórica: mu = (1/Z) * integral R * f(R) dR
    mu, _ = integrate.quad(lambda R: R * f(R), _sage_const_1p0 , _sage_const_2p0 ,
                            limit=_sage_const_200 , points=[_sage_const_1p001 ],
                            epsabs=_sage_const_1en10 , epsrel=_sage_const_1en10 )
    mu /= Z

    # Varianza teórica: sigma² = (1/Z) * integral (R-mu)² f(R) dR
    var, _ = integrate.quad(lambda R: (R-mu)**_sage_const_2  * f(R), _sage_const_1p0 , _sage_const_2p0 ,
                             limit=_sage_const_200 , points=[_sage_const_1p001 ],
                             epsabs=_sage_const_1en10 , epsrel=_sage_const_1en10 )
    var /= Z
    sigma = float(np.sqrt(var))

    # Momentos estandarizados M3, M4, M6
    M3, _ = integrate.quad(
        lambda R: ((R-mu)/sigma)**_sage_const_3  * f(R), _sage_const_1p0 , _sage_const_2p0 ,
        limit=_sage_const_200 , points=[_sage_const_1p001 ], epsabs=_sage_const_1en10 , epsrel=_sage_const_1en10 )
    M3 /= Z

    M4, _ = integrate.quad(
        lambda R: ((R-mu)/sigma)**_sage_const_4  * f(R), _sage_const_1p0 , _sage_const_2p0 ,
        limit=_sage_const_200 , points=[_sage_const_1p001 ], epsabs=_sage_const_1en10 , epsrel=_sage_const_1en10 )
    M4 /= Z

    M6, _ = integrate.quad(
        lambda R: ((R-mu)/sigma)**_sage_const_6  * f(R), _sage_const_1p0 , _sage_const_2p0 ,
        limit=_sage_const_200 , points=[_sage_const_1p001 ], epsabs=_sage_const_1en10 , epsrel=_sage_const_1en10 )
    M6 /= Z

    return {
        'Z': float(Z), 'mu': float(mu), 'sigma': float(sigma),
        'M3': float(M3), 'M4': float(M4), 'M6': float(M6)
    }

